			name: "synqnode/err",
			args: []string{
				"syntax", "querynode",
				"-F", "json",
				"/tmp/test.go", "invalid",
			},
			wantErr: true,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			env := newTestEnv(t)
			defer env.cleanup()
			if tt.setup != nil {
				tt.setup(env)
			}
			out, err := env.run(tt.args...)
			require.NoError(t, err)
			out = strings.TrimSpace(out)
			var m map[string]any
			require.NoError(t,
				json.Unmarshal(
					[]byte(out), &m,
				),
				"invalid JSON: %s", out,
			)
			if tt.wantErr {
				require.Equal(t,
					false, m["success"],
				)
				errMsg, ok :=
					m["error"].(string)
				require.True(t, ok,
					"missing error: %s", out,
				)
				require.NotEmpty(t, errMsg)
			} else if !tt.raw {
				require.Equal(t,
					true, m["success"],
				)
			}
		})
	}
