// separateArgs separates flags (and their values) from positional arguments,
// allowing flags to appear in any position within args. The "--" separator
// marks the end of flags; all subsequent arguments are treated as positional.
func separateArgs(fs *FlagSet, args []string) (flags, positional []string) {
	for i := 0; i < len(args); i++ {
		arg := args[i]

		// Handle "--" separator: everything after is positional
		if arg == "--" {
			positional = append(positional, args[i+1:]...)
			return
		}

		// Handle "-" as a positional argument (commonly means stdin)
		if arg == "-" {
			positional = append(positional, arg)
			continue
		}

		// Check if this looks like a flag (starts with -)
		if len(arg) > 1 && arg[0] == '-' {
			flags = append(flags, arg)

			// If flag doesn't have embedded value and is not a bool flag,
			// consume the next argument as the flag's value
			if !hasEmbeddedValue(arg) {
				name := extractFlagName(arg)
				if !isBoolFlag(fs, name) && i+1 < len(args) {
					i++
					flags = append(flags, args[i])
				}
			}
		} else {
			positional = append(positional, arg)
		}
	}
	return
}

