// separateArgsUntilFirstPositional separates flags from positional arguments,
// but stops parsing flags after the first positional argument is encountered.
// This is useful for parent commands that delegate to subcommands, where flags
// after the subcommand name belong to the subcommand, not the parent.
func separateArgsUntilFirstPositional(
	fs *FlagSet, args []string,
) (flags, rest []string) {
	for i := 0; i < len(args); i++ {
		arg := args[i]

		// Handle "--" separator: everything after is rest
