package cli

import (
	"flag"
	"strings"
)

func isBoolFlag(fs *FlagSet, name string) (is bool) {
	fs.VisitAll(func(f *flag.Flag) {
		if f.Name == name {
			_, is = f.Value.(interface{ IsBoolFlag() bool })
		}
	})
	return
}

// extractFlagName extracts the flag name from a flag argument.
// It handles both single-dash (-flag) and double-dash (--flag) prefixes,
// as well as the equals syntax (-flag=value or --flag=value).
