	"github.com/stretchr/testify/require"
)

const errFlagNotDefined = "flag provided but not defined"

var (
	indepeFlag bool
	anyFlag    int
)

func emptyFlagSet() *FlagSet {
	return NewFlagSet("Sad Panda")
}

func nonEmptyFlagSet() *FlagSet {
	fs := NewFlagSet("Els Segadors")
	fs.BoolVar(&indepeFlag, "independencia", true, "Ni Oblit, Ni Perdo.")
	fs.IntVar(&anyFlag, "any", 2019, "DUI Ja.")
	return fs
}

func requireError(t *testing.T, err error, expected interface{}) {
	switch expected.(type) {
	case string:
		require.NotNil(t, err)
		require.Contains(t, err.Error(), expected)
	default:
		require.Equal(t, expected, err)
	}
}

func recoverParsePanic(t *testing.T, testCase int) {
	err := recover()
	if err != nil {
		buf := make([]byte, 1<<16)
		runtime.Stack(buf, true)
		t.Fatalf("test case %d panic:%s\n%s\n", testCase, err, buf)
	}
}

func TestParse(t *testing.T) {
	tsuite := []struct {
		name string
		// input
		fs      *FlagSet
		expArgs int
		args    []string
		// output
		expectedArgs []string
		expectedRest []string
		expectedErr  interface{}
	}{
		// Basic error cases
		{"nil args", emptyFlagSet(), 0, nil, nil, nil, ErrInvalidArgs},
		{"empty args no expected", emptyFlagSet(), 0, []string{}, []string{}, []string{}, nil},
		{"empty args one expected", emptyFlagSet(), 1, []string{}, nil, nil, ErrInvalidArgs},

		// Basic positional args without flags
		{"single positional arg", emptyFlagSet(), 1, []string{"a"}, []string{"a"}, []string{}, nil},
		{"not enough positional args", emptyFlagSet(), 2, []string{"a"}, nil, nil, ErrInvalidArgs},
		{"positional args with rest", emptyFlagSet(), 2, []string{"a", "b", "c"}, []string{"a", "b"}, []string{"c"}, nil},

		// Undefined flags
		{"undefined flag with empty flagset", emptyFlagSet(), 0, []string{"-opt", "a"}, nil, nil, errFlagNotDefined},
		{"undefined flag with non-empty flagset", nonEmptyFlagSet(), 0, []string{"-opt", "a"}, nil, nil, errFlagNotDefined},

		// Flags before args (original behavior)
		{"bool flag before positional", nonEmptyFlagSet(), 0, []string{"-independencia", "a"}, []string{}, []string{"a"}, nil},
		{"value flag before positional", nonEmptyFlagSet(), 0, []string{"-any", "2017", "a"}, []string{}, []string{"a"}, nil},
		{"multiple flags before positional", nonEmptyFlagSet(), 1, []string{"-independencia", "-any", "2017", "a"}, []string{"a"}, []string{}, nil},

		// ===== NEW: Interspersed flags (flags after positional args) =====

		// Bool flag after single positional arg
		{"bool flag after positional", nonEmptyFlagSet(), 1, []string{"a", "-independencia"}, []string{"a"}, []string{}, nil},
		{"bool flag after positional no expected", nonEmptyFlagSet(), 0, []string{"a", "-independencia"}, []string{}, []string{"a"}, nil},

		// Value flag after positional arg
		{"value flag after positional", nonEmptyFlagSet(), 1, []string{"a", "-any", "2017"}, []string{"a"}, []string{}, nil},

		// Bool flag between two positional args
		{"bool flag between positionals", nonEmptyFlagSet(), 2, []string{"a", "-independencia", "b"}, []string{"a", "b"}, []string{}, nil},

		// Value flag between two positional args
		{"value flag between positionals", nonEmptyFlagSet(), 2, []string{"a", "-any", "2017", "b"}, []string{"a", "b"}, []string{}, nil},

		// Multiple flags interspersed
		{"flags before between and after", nonEmptyFlagSet(), 2, []string{"-independencia", "a", "-any", "2017", "b"}, []string{"a", "b"}, []string{}, nil},
		{"all flags after positionals", nonEmptyFlagSet(), 2, []string{"a", "b", "-independencia", "-any", "2017"}, []string{"a", "b"}, []string{}, nil},
		{"alternating flags and positionals", nonEmptyFlagSet(), 3, []string{"-independencia", "a", "-any", "2017", "b", "-independencia", "c"}, []string{"a", "b", "c"}, []string{}, nil},

		// Flags with rest args
		{"interspersed flags with rest", nonEmptyFlagSet(), 1, []string{"a", "-independencia", "b", "c"}, []string{"a"}, []string{"b", "c"}, nil},
		{"flags after positional with rest", nonEmptyFlagSet(), 1, []string{"a", "-any", "2017", "b"}, []string{"a"}, []string{"b"}, nil},

		// ===== Double-dash separator (--) =====
		{"double-dash treats rest as positional", nonEmptyFlagSet(), 2, []string{"--", "-independencia", "b"}, []string{"-independencia", "b"}, []string{}, nil},
		{"double-dash after flag", nonEmptyFlagSet(), 2, []string{"-independencia", "--", "-any", "b"}, []string{"-any", "b"}, []string{}, nil},
		{"double-dash after positional", nonEmptyFlagSet(), 3, []string{"a", "--", "-independencia", "b"}, []string{"a", "-independencia", "b"}, []string{}, nil},
		{"double-dash only", nonEmptyFlagSet(), 0, []string{"--"}, []string{}, []string{}, nil},
		{"double-dash with rest", nonEmptyFlagSet(), 1, []string{"--", "a", "b"}, []string{"a"}, []string{"b"}, nil},

		// ===== Edge cases =====
		{"single dash is positional", nonEmptyFlagSet(), 1, []string{"-"}, []string{"-"}, []string{}, nil},
		{"single dash with flag", nonEmptyFlagSet(), 1, []string{"-independencia", "-"}, []string{"-"}, []string{}, nil},

		// Undefined flag after positional should error
		{"undefined flag after positional", nonEmptyFlagSet(), 1, []string{"a", "-undefined"}, nil, nil, errFlagNotDefined},
		{"undefined flag between positionals", nonEmptyFlagSet(), 2, []string{"a", "-undefined", "b"}, nil, nil, errFlagNotDefined},

		// Double-dash flag prefix (--flag)
		{"double-dash bool flag", nonEmptyFlagSet(), 1, []string{"a", "--independencia"}, []string{"a"}, []string{}, nil},
		{"double-dash value flag", nonEmptyFlagSet(), 1, []string{"a", "--any", "2017"}, []string{"a"}, []string{}, nil},

		// Flag with = syntax
		{"flag with equals syntax", nonEmptyFlagSet(), 1, []string{"a", "-any=2017"}, []string{"a"}, []string{}, nil},
		{"flag with equals after positional", nonEmptyFlagSet(), 2, []string{"a", "-any=2017", "b"}, []string{"a", "b"}, []string{}, nil},
		{"double-dash flag with equals", nonEmptyFlagSet(), 1, []string{"a", "--any=2017"}, []string{"a"}, []string{}, nil},

		// Complex mixed scenarios
		{"complex mixed flags and positionals", nonEmptyFlagSet(), 3, []string{"-any", "2000", "a", "-independencia", "b", "-any", "2001", "c", "-independencia"}, []string{"a", "b", "c"}, []string{}, nil},
	}

	for i, _tcase := range tsuite {
		tcase := _tcase
		t.Run(tcase.name, func(t *testing.T) {
			defer recoverParsePanic(t, i)

			args, rest, err := Parse(tcase.fs, tcase.expArgs, tcase.args)

			requireError(t, err, tcase.expectedErr)
			assert.Equal(t, tcase.expectedArgs, args)
			assert.Equal(t, tcase.expectedRest, rest)
		})
	}
}

func TestParseOptions(t *testing.T) {
	defer recoverParsePanic(t, 0)
	indepeFlag = false
	anyFlag = 0

	_, _, err := Parse(nonEmptyFlagSet(), 0, []string{"-independencia", "-any", "1989"})
	requireError(t, err, nil)
	assert.Equal(t, true, indepeFlag)
	assert.Equal(t, 1989, anyFlag)
}

func TestParseInterspersedFlagValues(t *testing.T) {
	tsuite := []struct {
		name         string
		args         []string
		expArgs      int
		expectedBool bool
		expectedInt  int
	}{
		{
			name:         "flags before positional",
			args:         []string{"-independencia", "-any", "2000", "arg1"},
			expArgs:      1,
			expectedBool: true,
			expectedInt:  2000,
		},
		{
			name:         "bool flag after positional",
			args:         []string{"arg1", "-independencia"},
			expArgs:      1,
			expectedBool: true,
			expectedInt:  2019, // default
		},
		{
			name:         "value flag after positional",
			args:         []string{"arg1", "-any", "1714"},
			expArgs:      1,
			expectedBool: true, // default
			expectedInt:  1714,
		},
		{
			name:         "flags between positionals",
			args:         []string{"arg1", "-independencia", "-any", "1939", "arg2"},
			expArgs:      2,
			expectedBool: true,
			expectedInt:  1939,
		},
		{
			name:         "flags scattered everywhere",
			args:         []string{"-any", "1000", "arg1", "-independencia", "arg2", "-any", "2000"},
			expArgs:      2,
			expectedBool: true,
			expectedInt:  2000, // last value wins
		},
		{
			name:         "flag with equals syntax after positional",
			args:         []string{"arg1", "-any=1492"},
			expArgs:      1,
			expectedBool: true, // default
			expectedInt:  1492,
		},
		{
			name:         "double-dash stops flag parsing",
			args:         []string{"-any", "1000", "--", "-any", "2000"},
			expArgs:      2,
			expectedBool: true, // default
			expectedInt:  1000, // only first -any is parsed
		},
	}

	for _, _tcase := range tsuite {
		tcase := _tcase
		t.Run(tcase.name, func(t *testing.T) {
			// Reset to defaults
			indepeFlag = true  // default from nonEmptyFlagSet
			anyFlag = 2019     // default from nonEmptyFlagSet

			fs := nonEmptyFlagSet()
			args, _, err := Parse(fs, tcase.expArgs, tcase.args)

			require.NoError(t, err)
			require.Len(t, args, tcase.expArgs)
			assert.Equal(t, tcase.expectedBool, indepeFlag, "bool flag value mismatch")
			assert.Equal(t, tcase.expectedInt, anyFlag, "int flag value mismatch")
		})
	}
}

