// ParseForSubcommand parses flags that appear before the first positional
// argument (typically a subcommand name) and returns the rest. This is designed
// for parent commands that delegate to subcommands - flags appearing after the
// subcommand name are left for the subcommand to parse.
//
// Example:
//
//	fs := NewFlagSet("parent")
//	fs.BoolVar(&verbose, "v", false, "verbose")
//
//	// "-v" is parsed, "subcommand -F json arg" is returned as rest
//	ParseForSubcommand(fs, []string{"-v", "subcommand", "-F", "json", "arg"})
//
// Note that ErrHelp is returned if -h or --help flags are in the parsed flags.
func ParseForSubcommand(fs *FlagSet, args []string) (rest []string, err error) {
	if args == nil || fs == nil {
		err = ErrInvalidArgs
		return
	}

	flags, rest := separateArgsUntilFirstPositional(fs, args)

	if len(flags) > 0 {
		err = fs.Parse(flags)
		if err == flag.ErrHelp || fs.help {
			err = ErrHelp
		}
		if err != nil {
			return nil, err
		}
	}

	// Ensure we return empty slice instead of nil for consistency
	if rest == nil {
		rest = []string{}
	}
	return rest, nil
}

