package cli

import (
	"flag"
	"strings"
)

func isBoolFlag(fs *FlagSet, name string) (is bool) {
	fs.VisitAll(func(f *flag.Flag) {
		if f.Name == name {
			_, is = f.Value.(interface{ IsBoolFlag() bool })
		}
	})
	return
}

// extractFlagName extracts the flag name from a flag argument.
// It handles both single-dash (-flag) and double-dash (--flag) prefixes,
// as well as the equals syntax (-flag=value or --flag=value).
func extractFlagName(arg string) string {
	name := strings.TrimLeft(arg, "-")
	if eqIdx := strings.Index(name, "="); eqIdx != -1 {
		name = name[:eqIdx]
	}
	return name
}

// hasEmbeddedValue checks if a flag argument contains an embedded value
// using the equals syntax (-flag=value or --flag=value).
func hasEmbeddedValue(arg string) bool {
	return strings.Contains(arg, "=")
}

// separateArgs separates flags (and their values) from positional arguments,
// allowing flags to appear in any position within args. The "--" separator
// marks the end of flags; all subsequent arguments are treated as positional.
func separateArgs(fs *FlagSet, args []string) (flags, positional []string) {
	for i := 0; i < len(args); i++ {
		arg := args[i]

		// Handle "--" separator: everything after is positional
		if arg == "--" {
			positional = append(positional, args[i+1:]...)
			return
		}

		// Handle "-" as a positional argument (commonly means stdin)
		if arg == "-" {
			positional = append(positional, arg)
			continue
		}

		// Check if this looks like a flag (starts with -)
		if len(arg) > 1 && arg[0] == '-' {
			flags = append(flags, arg)

			// If flag doesn't have embedded value and is not a bool flag,
			// consume the next argument as the flag's value
			if !hasEmbeddedValue(arg) {
				name := extractFlagName(arg)
				if !isBoolFlag(fs, name) && i+1 < len(args) {
					i++
					flags = append(flags, args[i])
				}
			}
		} else {
			positional = append(positional, arg)
		}
	}
	return
}

// separateArgsUntilFirstPositional separates flags from positional arguments,
// but stops parsing flags after the first positional argument is encountered.
// This is useful for parent commands that delegate to subcommands, where flags
// after the subcommand name belong to the subcommand, not the parent.
func separateArgsUntilFirstPositional(
	fs *FlagSet, args []string,
) (flags, rest []string) {
	for i := 0; i < len(args); i++ {
		arg := args[i]

		// Handle "--" separator: everything after is rest
		if arg == "--" {
			rest = append(rest, args[i+1:]...)
			return
		}

		// Handle "-" as a positional argument (commonly means stdin)
		if arg == "-" {
			rest = append(rest, args[i:]...)
			return
		}

		// Check if this looks like a flag (starts with -)
		if len(arg) > 1 && arg[0] == '-' {
			flags = append(flags, arg)

			// If flag doesn't have embedded value and is not a bool flag,
			// consume the next argument as the flag's value
			if !hasEmbeddedValue(arg) {
				name := extractFlagName(arg)
				if !isBoolFlag(fs, name) && i+1 < len(args) {
					i++
					flags = append(flags, args[i])
				}
			}
		} else {
			// First positional argument found - rest of args go to subcommand
			rest = append(rest, args[i:]...)
			return
		}
	}
	return
}

// Parse parses all flags in args and returns the remaining arguments
// as defined by expectedArgs. Flags can appear in any position within
// args (interspersed with positional arguments).
//
// The "--" separator marks the end of flags; all subsequent arguments
// are treated as positional arguments regardless of their format.
//
// Example:
//
//	var myBoolOpt
//	fs := NewFlagSet("ie", []string{"my-mandatory-arg"})
//	fs.BoolVar(&myBoolOpt, "bool-opt", false, "bool opt flag")
//
//	fs.Parse([]string{"-bool-opt"}) // returns nil, ErrInvalidArgs
//	fs.Parse([]string{"my-value"}) // returns []string{"my-value"}, nil
//	fs.Parse([]string{"-bool-opt", "my-value"}) // returns []string{"my-value"}, nil
//	fs.Parse([]string{"my-value", "-bool-opt"}) // returns []string{"my-value"}, nil
//	fs.Parse([]string{"--", "-bool-opt"}) // returns []string{"-bool-opt"}, nil
//
// Note that ErrHelp is returned if -h or --help flags are in args.
func Parse(fs *FlagSet, expectedArgs int, args []string) (
	actualArgs []string, rest []string, err error,
) {
	if args == nil || fs == nil {
		err = ErrInvalidArgs
		return
	}

	flags, positional := separateArgs(fs, args)

	if len(flags) > 0 {
		err = fs.Parse(flags)
		if err == flag.ErrHelp || fs.help {
			err = ErrHelp
		}
		if err != nil {
			return
		}
	}

	if expectedArgs > len(positional) {
		err = ErrInvalidArgs
		return
	}

	// Ensure we return empty slices instead of nil for backward compatibility
	actualArgs = positional[:expectedArgs]
	if actualArgs == nil {
		actualArgs = []string{}
	}
	rest = positional[expectedArgs:]
	if rest == nil {
		rest = []string{}
	}
	return
}

// ParseUsage calls Parse and handles ErrHelp by returning false. If flags are parsed with no
// errors and usage flag is not passed, then this function returns true.
func ParseUsage(cli CLI, fs *FlagSet, expectedArgs int, args []string) (
	rargs, rest []string, ok bool, err error,
) {

	args, rest, err = Parse(fs, expectedArgs, args)
	if err != nil {
		if handleCommonErrors(cli, err) {
			err = nil
		}
		return
	}
	ok = true
	rargs = args
	return
}

// ParseForSubcommand parses flags that appear before the first positional
// argument (typically a subcommand name) and returns the rest. This is designed
// for parent commands that delegate to subcommands - flags appearing after the
// subcommand name are left for the subcommand to parse.
//
// Example:
//
//	fs := NewFlagSet("parent")
//	fs.BoolVar(&verbose, "v", false, "verbose")
//
//	// "-v" is parsed, "subcommand -F json arg" is returned as rest
//	ParseForSubcommand(fs, []string{"-v", "subcommand", "-F", "json", "arg"})
//
// Note that ErrHelp is returned if -h or --help flags are in the parsed flags.
func ParseForSubcommand(fs *FlagSet, args []string) (rest []string, err error) {
	if args == nil || fs == nil {
		err = ErrInvalidArgs
		return
	}

	flags, rest := separateArgsUntilFirstPositional(fs, args)

	if len(flags) > 0 {
		err = fs.Parse(flags)
		if err == flag.ErrHelp || fs.help {
			err = ErrHelp
		}
		if err != nil {
			return nil, err
		}
	}

	return rest, nil
}

