   436→type multiFlag []string
   437→
   438→func (m *multiFlag) String() string { return "" }
   439→func (m *multiFlag) Set(v string) error {
   440→	*m = append(*m, v)
   441→	return nil
   442→}
   443→
   444→func parseUpdateArgs(
   445→	args []string,
   446→) ([]storageapi.Update, error) {
   447→	if len(args)%2 != 0 {
   448→		return nil, fmt.Errorf(
   449→			"update requires pairs of" +
   450→				" <field.path> <value>",
   451→		)
   452→	}
   453→	updates := make(
   454→		[]storageapi.Update, 0, len(args)/2,
   455→	)
   456→	for i := 0; i < len(args); i += 2 {
   457→		path := strings.Split(args[i], ".")
   458→		for _, p := range path {
   459→			if p == "" {
   460→				return nil, fmt.Errorf(
   461→					"empty segment in field path %q",
   462→					args[i],
   463→				)
   464→			}
   465→		}
   466→		var value any
   467→		if err := json.Unmarshal(
   468→			[]byte(args[i+1]), &value,
   469→		); err != nil {
   470→			value = args[i+1]
   471→		}
   472→		updates = append(updates, storageapi.Update{
   473→			FieldPath: path, Value: value,
   474→		})
   475→	}
   476→	return updates, nil
   477→}
   478→
   479→type jsonPrecondition struct {
   480→	Path  []string `json:"path"`
   481→	Value any      `json:"value"`
   482→}
   483→
   484→func parsePreconditions(
   485→	s string,
   486→) ([]storageapi.Precondition, error) {
   487→	var raw []jsonPrecondition
   488→	if err := json.Unmarshal([]byte(s), &raw); err != nil {
   489→		return nil, fmt.Errorf(
   490→			"invalid preconditions JSON: %w", err,
   491→		)
   492→	}
   493→	ret := make([]storageapi.Precondition, len(raw))
   494→	for i, p := range raw {
   495→		ret[i] = storageapi.Precondition{
   496→			FieldPath: p.Path, Value: p.Value,
   497→		}
   498→	}
   499→	return ret, nil
   500→}
   501→
   502→type jsonFilter struct {
   503→	Path  []string `json:"path"`
   504→	Op    string   `json:"op"`
   505→	Value any      `json:"value"`
   506→}
   507→
   508→func parseFilters(
   509→	raw []string,
   510→) ([]storageapi.Filter, error) {
   511→	var ret []storageapi.Filter
   512→	for _, s := range raw {
   513→		var f jsonFilter
   514→		if err := json.Unmarshal(
   515→			[]byte(s), &f,
   516→		); err != nil {
   517→			return nil, fmt.Errorf(
   518→				"invalid filter JSON %q: %w", s, err,
   519→			)
   520→		}
   521→		ret = append(ret, storageapi.Filter{
   522→			Field: storageapi.Field{
   523→				FieldPath: f.Path,
   524→				Value:     f.Value,
   525→			},
   526→			Op: storageapi.Op(f.Op),
   527→		})
   528→	}
   529→	return ret, nil
   530→}
   531→
   532→func storageIterToGeneric(
   533→	_ context.Context,
   534→	sit storageapi.Iterator,
   535→) iterator.Iterator[map[string]any] {
   536→	return iterator.FromFunc(
   537→		func(ctx context.Context) (
   538→			map[string]any, bool, error,
   539→		) {
   540→			if !sit.HasNext() {
   541→				return nil, false, nil
   542→			}
   543→			var doc map[string]any
   544→			if err := sit.NextTo(&doc); err != nil {
   545→				return nil, false, err
   546→			}
   547→			return doc, true, nil
   548→		},
   549→		sit.Close,
   550→	)
   551→}
