	if !ok || err != nil {
		return err
	}
	orient, err := parseOrientation(c.orientation)
	if err != nil {
		return err
	}
	wid, err := parseWindowID(rargs[0])
	if err != nil {
		return err
	}
	h, err := resolveHandler(ctx, c.app, rargs[1])
	if err != nil {
		return err
	}
	w, err := c.app.getWorkspace()
	if err != nil {
		return err
	}
	win, err := w.WindowManager(ctx).Split(
