	)
	c.fs.StringVar(
		&c.align, "a", "",
		"Alignment: default|left|right|"+
			"top|bottom|centered",
	)
	c.fs.IntVar(&c.offsetX, "x", 0, "X offset")
	c.fs.IntVar(&c.offsetY, "y", 0, "Y offset")
	return c
