	defer func() {
		retErr = formatError(c.format, retErr)
	}()
	_, _, ok, err := cli.ParseUsage(
		c, c.fs, 0, args,
	)
	if !ok || err != nil {
		return err
	}
	if c.format == "table" {
		return fmt.Errorf(
			"table format not supported" +
				" for storage list",
		)
	}
	filters, err := parseFilters(c.filters)
	if err != nil {
		return err
	}
	w, err := c.app.getWorkspace()
	if err != nil {
		return err
	}
	sit, err := w.Storage(ctx).List(ctx, filters)
	if err != nil {
