			if tt.wantErr {
				require.Equal(t,
					false, m["success"],
				)
				errMsg, ok :=
					m["error"].(string)
				require.True(t, ok,
					"missing error: %s", out,
				)
				require.NotEmpty(t, errMsg)
			} else if !tt.raw {
				require.Equal(t,
					true, m["success"],
				)
			}
		})
	}
}

