				"syntax", "searchnode",
				"-F", "json", "func",
			},
			raw: true,
		},
		{
			name: "synquery/ok",
			setup: func(env *testEnv) {},
			args: []string{
				"syntax", "query",
				"-F", "json",
				"/tmp/test.go",
				"(package_clause) @pkg",
			},
