			wantErr: true,
		},
		{
			name: "split/err",
			args: []string{
				"wm", "split", "-F", "json",
				"-o", "bad",
				"42", "file:///tmp/test.txt",
			},
			wantErr: true,
		},
		{
			name: "setcnt/err",
			args: []string{
				"wm", "set-content",
				"-F", "json",
				"abc", "file:///tmp/test.txt",
			},
			wantErr: true,
		},
		{
			name: "float/err",
			args: []string{
				"wm", "floating",
				"-F", "json",
				"file:///tmp/test.txt",
			},
			wantErr: true,
